     1→/**
     2→ * @file Tool scanner utility
     3→ * @module utils/tool-scanner
     4→ * 
     5→ * @remarks
     6→ * This module provides functionality to dynamically discover and load CLI tools
     7→ * from the filesystem. It scans for files matching a pattern and attempts to
     8→ * load their tool registrations.
     9→ */
    10→
    11→import { readdir } from 'fs/promises';
    12→import { join, resolve } from 'path';
    13→import { pathToFileURL } from 'url';
    14→import { logger } from './logger.js';
    15→import type { 
    16→  ToolRegistry, 
    17→  ToolScanOptions, 
    18→  ToolScanResult, 
    19→  ToolRegistration 
    20→} from '../types/tool-registry.js';
    21→
    22→/**
    23→ * Tools that should be excluded from the tool registry
    24→ * These tools are deactivated for security and multi-tenancy reasons
    25→ */
    26→const EXCLUDED_TOOLS = new Set([
    27→  'mittwald_login_reset',
    28→  'mittwald_login_token'
    29→]);
    30→
    31→/**
    32→ * Default options for tool scanning
    33→ */
    34→const DEFAULT_SCAN_OPTIONS: ToolScanOptions = {
    35→  baseDir: '',
    36→  pattern: '*-cli.ts',
    37→  recursive: true
    38→};
    39→
    40→/**
    41→ * Scans a directory recursively for CLI tool files
    42→ * 
    43→ * @param dir - Directory to scan
    44→ * @param pattern - File pattern to match (default: *-cli.ts)
    45→ * @returns Array of file paths matching the pattern
    46→ */
    47→async function scanDirectory(dir: string, pattern: string = '*-cli.ts'): Promise<string[]> {
    48→  const files: string[] = [];
    49→  
    50→  try {
    51→    const entries = await readdir(dir, { withFileTypes: true });
    52→    
    53→    for (const entry of entries) {
    54→      const fullPath = join(dir, entry.name);
    55→      
    56→      if (entry.isDirectory()) {
    57→        // Recursively scan subdirectories
    58→        const subFiles = await scanDirectory(fullPath, pattern);
    59→        files.push(...subFiles);
    60→      } else if (entry.isFile()) {
    61→        // Check if file matches pattern
    62→        if (entry.name.endsWith('-cli.ts') || entry.name.endsWith('-cli.js')) {
    63→          files.push(fullPath);
    64→        }
    65→      }
    66→    }
    67→  } catch (error) {
    68→    logger.warn(`Failed to scan directory ${dir}:`, error);
    69→  }
    70→  
    71→  return files;
    72→}
    73→
    74→/**
    75→ * Loads a tool registration from a file
    76→ * 
    77→ * @param filePath - Path to the tool file
    78→ * @returns Tool registration or null if failed
    79→ */
    80→async function loadToolFromFile(filePath: string): Promise<ToolRegistration | null> {
    81→  try {
    82→    // Convert file path to URL for dynamic import
    83→    const fileUrl = pathToFileURL(filePath).href;
    84→    
    85→    // Dynamic import the module
    86→    const module = await import(fileUrl);
